// 1. Sadə tuple: Sabit uzunluqlu siyahı
type UserInfo = [string, number]; // Ad və yaş
let user: UserInfo = ["Murad", 23];
// user = [23, "Murad"]; // Xəta: tiplər yanlış sırayla
// user = ["Murad", 23, true]; // Xəta: çox element

// 2. Tuple funksiyada qaytarma dəyəri kimi
function getProduct(): [string, number] {
  return ["Laptop", 1200];
}
const product = getProduct();
console.log(`${product[0]}: $${product[1]}`); // Çıxış: Laptop: $1200

// 3. Readonly tuple: Dəyişdirilməz siyahı
type FixedProduct = readonly [string, number];
let fixedItem: FixedProduct = ["Mouse", 25];
// fixedItem[0] = "Keyboard"; // Xəta: readonly tuple dəyişdirilə bilməz

// 4. Opsiyonel elementlər ilə tuple
type Order = [string, number, boolean?]; // Son element isteğe bağlı
let order1: Order = ["Book", 15]; // Boolean olmadan işləyir
let order2: Order = ["Pen", 5, true];
console.log(order1); // Çıxış: ["Book", 15]
console.log(order2); // Çıxış: ["Pen", 5, true]

// 5. Tuple ilə funksiya parametri
function showUserInfo(user: [string, number]): string {
  return `${user[0]}: ${user[1]} yaş`;
}
console.log(showUserInfo(["Alice", 25])); // Çıxış: Alice: 25 yaş

// 6. Çoxlu tipli tuple
type ItemDetails = [string, number, boolean, string?]; // Fərqli tiplər
let item: ItemDetails = ["Keyboard", 50, true]; // Son element isteğe bağlı
console.log(item); // Çıxış: ["Keyboard", 50, true]

// Sadə mağaza sistemi
type Product = [string, number, boolean?]; // Ad, qiymət, mövcudluq (opsiyonel)
let product1: Product = ["Laptop", 1200, true];
let product2: Product = ["Mouse", 25]; // Mövcudluq olmadan

function showProduct(product: Product): string {
  const availability = product[2] !== undefined ? (product[2] ? "mövcuddur" : "mövcud deyil") : "məlumat yoxdur";
  return `${product[0]}: $${product[1]}, ${availability}`;
}

console.log(showProduct(product1)); // Çıxış: Laptop: $1200, mövcuddur
console.log(showProduct(product2)); // Çıxış: Mouse: $25, məlumat yoxdur

// Readonly tuple ilə sabit məlumat
type Category = readonly [string, string];
const category: Category = ["Electronics", "Laptop"];
// category[0] = "Books"; // Xəta: readonly tuple dəyişdirilə bilməz

