// 1. Simple tuple: Fixed-length list
type UserInfo = [string, number]; // Name and age
let user: UserInfo = ["Murad", 23];
// user = [23, "Murad"]; // Error: types in wrong order
// user = ["Murad", 23, true]; // Error: too many elements

// 2. Tuple as function return type
function getProduct(): [string, number] {
  return ["Laptop", 1200];
}
const product = getProduct();
console.log(`${product[0]}: $${product[1]}`); // Output: Laptop: $1200

// 3. Readonly tuple: Immutable list
type FixedProduct = readonly [string, number];
let fixedItem: FixedProduct = ["Mouse", 25];
// fixedItem[0] = "Keyboard"; // Error: readonly tuple cannot be modified

// 4. Optional elements in tuple
type Order = [string, number, boolean?]; // Last element is optional
let order1: Order = ["Book", 15]; // Works without boolean
let order2: Order = ["Pen", 5, true];
console.log(order1); // Output: ["Book", 15]
console.log(order2); // Output: ["Pen", 5, true]

// 5. Tuple as function parameter
function showUserInfo(user: [string, number]): string {
  return `${user[0]}: ${user[1]} years old`;
}
console.log(showUserInfo(["Alice", 25])); // Output: Alice: 25 years old

// 6. Multi-type tuple
type ItemDetails = [string, number, boolean, string?]; // Different types
let item: ItemDetails = ["Keyboard", 50, true]; // Last element optional
console.log(item); // Output: ["Keyboard", 50, true]

// Simple store system
type Product = [string, number, boolean?]; // Name, price, availability (optional)
let product1: Product = ["Laptop", 1200, true];
let product2: Product = ["Mouse", 25]; // Without availability

function showProduct(product: Product): string {
  const availability = product[2] !== undefined ? (product[2] ? "in stock" : "out of stock") : "no info";
  return `${product[0]}: $${product[1]}, ${availability}`;
}

console.log(showProduct(product1)); // Output: Laptop: $1200, in stock
console.log(showProduct(product2)); // Output: Mouse: $25, no info

// Readonly tuple for fixed data
type Category = readonly [string, string];
const category: Category = ["Electronics", "Laptop"];
// category[0] = "Books"; // Error: readonly tuple cannot be modified

